var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEADER_NPC_NANAHARA2_E","text":{"KOREA":"침식체 섬멸 확인. 침식파 계수도 꾸준히 감소하고 있습니다.","JPN":"侵食体の殲滅を確認。侵食波係数もどんどん減少しています。","ENG":"C.O. termination confirmed. Corruption ray level decreasing.","TWN":"侵蝕體確認殲滅，侵蝕波係數也持續減少中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"LEADER_NPC_NANAHARA2_E","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다들 고생하셨어요. 피해가 더 커지기 전에 해결되어 다행입니다.","JPN":"みなさん、お疲れさまでした。被害が大きくなる前に解決できてよかったです。","ENG":"Good work, everyone. I am relieved things ended before they got out of hand.","TWN":"大家都辛苦了，幸好在傷亡擴大前處理完畢。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"정말 감사합니다. 다른 지역도 이제 대부분 소강상태라는군요.","JPN":"本当にありがとうございます。他の地域ももうほとんどが小康状態のようです。","ENG":"Thank you so much. I hear most of the other areas are cleared as well.","TWN":"真的非常感謝，其他地區的情況大部分也都已經和緩下來。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"상처 부위는 아직 괜찮으신가요?","JPN":"傷の方は大丈夫ですか？","ENG":"How is your wound?","TWN":"你受傷的地方還好嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"네, 치료해주신 덕분에……","JPN":"はい、治療してくださったおかげで……","ENG":"Good, thanks to you...","TWN":"是，多虧你替我治療……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"저기, 떠나기 전에 하나만 물어봐도 되겠습니까?","JPN":"あの、出発される前に一つだけ聞いてもいいですか？","ENG":"Um, would you mind if I ask you something before you leave?","TWN":"那個，離開前我可以問一個問題嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"네, 말씀하세요.","JPN":"はい、どうぞ。","ENG":"No, please do.","TWN":"當然，你請問。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"얼마 전부터 침식사태 때마다 활약을 하고 있다던데, 왜 태스크포스에 소속되지도 않은 분들이 이런 위험한 일을 도우시는 거죠?","JPN":"少し前から侵食事態が発生するたびにご活躍されているようですが、どうしてタスクフォースにも所属していない方たちがこのような危険な仕事を手伝っているのですか？","ENG":"I hear that you’ve been helping us with the Corruption disasters. Why? You’re not even a TASKFORCE.","TWN":"我聽說從前陣子開始，每次發生侵蝕事件時你們都會出手相助，你們又不屬於特遣勢力，為什麼願意不顧生命危險幫我們呢？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건…….","JPN":"それは……","ENG":"That is...","TWN":"那是因為……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희에게는 그런 책임을 질 의무가 있기 때문입니다.","JPN":"私たちにはそのような責任を取る義務があるからです。","ENG":"That is because we are responsible for it.","TWN":"我們有義務擔負起這個責任。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_A","text":{"KOREA":"네? 대체 누가 초자연적인 재해를 두고 사람에게 책임을 묻습니까?","JPN":"はい？　いったい誰が超自然的な災害で人に責任を問うんですか？","ENG":"Huh? Why would anyone be responsible for a supernatural disaster?","TWN":"什麼？有誰會拿超自然的災難向人究責呢？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저희의 대비가 미흡한 탓에 풀려나서는 안 될 악이 깨어났고, 그 여파로 침식의 경계가 약해진 것이니까요.","JPN":"私たちの備えが不十分だったせいで解放されてはならない悪が目覚め、そのあおりで侵食の境界が脆くなっているのですから。","ENG":"It is because we were unprepared, which led to the awakening of a great evil. That is why the Corruption boundaries weakened.","TWN":"因為我們的疏失，喚醒禁忌的惡，才會導致侵蝕的警戒變弱。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"……뭐, 어떤 사정이 있는지 모르겠지만 그런 죄 지은 표정은 짓지 마세요.","JPN":"……まあ、どんな事情があるのかは知りませんが、そんな罪を犯したような顔をしないでください。","ENG":"...I don’t know what your story is, but don’t feel so guilty about it.","TWN":"……嗯，雖然我不清楚究竟發生什麼事，但請你不要一臉愧疚的樣子。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_B","text":{"KOREA":"저희에게 당신들은 영웅이니까요.","JPN":"私たちにとってあなたたちは英雄なんですから。","ENG":"You’re a hero to us.","TWN":"因為對我們來說，你們是英雄。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DEFENDER_NPC_NANAHARA2_A","text":{"KOREA":"그럼요. 시민들도 고마워할 겁니다.","JPN":"そうです。市民も感謝してるはずですよ。","ENG":"Of course. Even the civilians would be grateful.","TWN":"是啊，市民也會很感謝你們的。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"DEFENDER_NPC_NANAHARA2_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그런데, 저 분들은?","JPN":"ところで、あの方々は？","ENG":"Oh, by the way, who are those people?","TWN":"不過，他們是誰？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"DEFENDER_NPC_NANAHARA2_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};